// Get data from the trigger
const triggerData = $input.item.json;

// Extract the date components we need
const dayOfWeek = triggerData['Day of week'];
const year = triggerData.Year;
const month = triggerData.Month;
const dayOfMonth = triggerData['Day of month'];

// Create readable today format
const today = `${dayOfWeek}, ${month} ${parseInt(dayOfMonth)}, ${year}`;

// Create month/day format for database lookups
const monthDay = `${new Date(`${month} 1, ${year}`).getMonth() + 1}/${parseInt(dayOfMonth)}`;

// Create API date format (MM-DD) for Catholic Readings API
const monthNum = (new Date(`${month} 1, ${year}`).getMonth() + 1).toString().padStart(2, '0');
const dayNum = dayOfMonth.padStart(2, '0');
const apiDateFormat = `${monthNum}-${dayNum}`;

// Benedictine themes by day of week
const themes = {
  'Sunday': 'Worship & Community',
  'Monday': 'Humility & Simplicity',
  'Tuesday': 'Stability',
  'Wednesday': 'Listening',
  'Thursday': 'Hospitality & Kindness',
  'Friday': 'Sacrifice & Repentance',
  'Saturday': 'Rest & Beauty'
};

// Create USCCB date format (MMDDYY)
const yearShort = year.slice(-2);
const usccbDate = `${monthNum}${dayNum}${yearShort}`;

console.log(`Processing date: ${today}`);
console.log(`Month/Day format: ${monthDay}`);
console.log(`API format: ${apiDateFormat}`);
console.log(`USCCB format: ${usccbDate}`);

return {
  today: today,
  dayOfWeek: dayOfWeek,
  monthDay: monthDay,
  apiDateFormat: apiDateFormat,
  theme: themes[dayOfWeek] || 'Prayer',
  usccbLink: `https://bible.usccb.org/bible/readings/${usccbDate}.cfm`,
  year: year,
  month: month,
  dayOfMonth: dayOfMonth
};

// Merge readings with saint data - get data from the correct sources
const readings = $('Get Readings').first().json;
const saints = $input.first().json;
const dateInfo = $('Format Date').first().json;

console.log('Readings data:', readings);
console.log('Saints data:', saints);
console.log('Date info:', dateInfo);

return {
  ...dateInfo,
  readings: readings.readings,
  season: readings.season,
  usccbLink: readings.usccbLink,
  saint: saints.saint,
  hasSaint: true
};

// Continue with readings only (no saint for today)
const readings = $('Get Readings').item.json;
const dateInfo = $('Format Date').item.json;

return {
  ...dateInfo,
  readings: readings.readings,
  season: readings.season,
  usccbLink: readings.usccbLink,
  saint: null,
  hasSaint: false
};

